const crypto = require('crypto');

// --- Password Hashing ---

const HASH_ITERATIONS = 100000;
const HASH_KEYLEN = 64;
const HASH_DIGEST = 'sha512';
const SALT_LENGTH = 32;

function hashPassword(password) {
  return new Promise((resolve, reject) => {
    const salt = crypto.randomBytes(SALT_LENGTH).toString('hex');
    crypto.pbkdf2(password, salt, HASH_ITERATIONS, HASH_KEYLEN, HASH_DIGEST, (err, derivedKey) => {
      if (err) return reject(err);
      resolve(`${salt}:${HASH_ITERATIONS}:${HASH_KEYLEN}:${HASH_DIGEST}:${derivedKey.toString('hex')}`);
    });
  });
}

function verifyPassword(password, storedHash) {
  return new Promise((resolve, reject) => {
    const [salt, iterations, keylen, digest, hash] = storedHash.split(':');
    crypto.pbkdf2(password, salt, parseInt(iterations), parseInt(keylen), digest, (err, derivedKey) => {
      if (err) return reject(err);
      resolve(crypto.timingSafeEqual(Buffer.from(hash, 'hex'), derivedKey));
    });
  });
}

// --- Secure Session/Token Handling ---

const TOKEN_EXPIRY_MS = 60 * 60 * 1000; // 1 hour
const tokenStore = new Map();

function generateSessionToken(userId) {
  const token = crypto.randomBytes(48).toString('hex');
  const expiresAt = Date.now() + TOKEN_EXPIRY_MS;
  tokenStore.set(token, { userId, expiresAt, createdAt: Date.now() });
  return { token, expiresAt };
}

function validateSessionToken(token) {
  const session = tokenStore.get(token);
  if (!session) return null;
  if (Date.now() > session.expiresAt) {
    tokenStore.delete(token);
    return null;
  }
  return session;
}

function revokeSessionToken(token) {
  return tokenStore.delete(token);
}

function cleanupExpiredTokens() {
  const now = Date.now();
  for (const [token, session] of tokenStore.entries()) {
    if (now > session.expiresAt) {
      tokenStore.delete(token);
    }
  }
}

setInterval(cleanupExpiredTokens, 5 * 60 * 1000);

// --- Rate Limiting ---

const rateLimitStore = new Map();

const RATE_LIMIT_CONFIG = {
  login: { windowMs: 15 * 60 * 1000, maxAttempts: 5 },
  register: { windowMs: 60 * 60 * 1000, maxAttempts: 3 },
  tokenRefresh: { windowMs: 5 * 60 * 1000, maxAttempts: 10 },
};

function checkRateLimit(identifier, action = 'login') {
  const config = RATE_LIMIT_CONFIG[action] || RATE_LIMIT_CONFIG.login;
  const key = `${action}:${identifier}`;
  const now = Date.now();
  let record = rateLimitStore.get(key);

  if (!record || now - record.windowStart > config.windowMs) {
    record = { attempts: 0, windowStart: now };
    rateLimitStore.set(key, record);
  }

  record.attempts += 1;

  if (record.attempts > config.maxAttempts) {
    const retryAfterMs = config.windowMs - (now - record.windowStart);
    return {
      allowed: false,
      retryAfterMs,
      remaining: 0,
    };
  }

  return {
    allowed: true,
    retryAfterMs: 0,
    remaining: config.maxAttempts - record.attempts,
  };
}

function resetRateLimit(identifier, action = 'login') {
  const key = `${action}:${identifier}`;
  rateLimitStore.delete(key);
}

// Cleanup stale rate limit entries periodically
setInterval(() => {
  const now = Date.now();
  for (const [key, record] of rateLimitStore.entries()) {
    const action = key.split(':')[0];
    const config = RATE_LIMIT_CONFIG[action] || RATE_LIMIT_CONFIG.login;
    if (now - record.windowStart > config.windowMs) {
      rateLimitStore.delete(key);
    }
  }
}, 10 * 60 * 1000);

// --- In-Memory User Store (prototype only) ---

const users = new Map();

async function registerUser(username, password, ipAddress) {
  const rateCheck = checkRateLimit(ipAddress, 'register');
  if (!rateCheck.allowed) {
    return {
      success: false,
      error: `Registration rate limit exceeded. Retry after ${Math.ceil(rateCheck.retryAfterMs / 1000)}s`,
    };
  }

  if (!username || !password) {
    return { success: false, error: 'Username and password are required' };
  }

  if (password.length < 8) {
    return { success: false, error: 'Password must be at least 8 characters' };
  }

  if (users.has(username.toLowerCase())) {
    return { success: false, error: 'Username already exists' };
  }

  const hashedPassword = await hashPassword(password);
  const userId = crypto.randomBytes(16).toString('hex');

  users.set(username.toLowerCase(), {
    userId,
    username,
    hashedPassword,
    createdAt: Date.now(),
  });

  const session = generateSessionToken(userId);

  return {
    success: true,
    userId,
    token: session.token,
    expiresAt: session.expiresAt,
  };
}

async function loginUser(username, password, ipAddress) {
  const rateCheck = checkRateLimit(ipAddress, 'login');
  if (!rateCheck.allowed) {
    return {
      success: false,
      error: `Too many login attempts. Retry after ${Math.ceil(rateCheck.retryAfterMs / 1000)}s`,
      remaining: 0,
    };
  }

  if (!username || !password) {
    return { success: false, error: 'Username and password are required', remaining: rateCheck.remaining };
  }

  const user = users.get(username.toLowerCase());
  if (!user) {
    return { success: false, error: 'Invalid credentials', remaining: rateCheck.remaining };
  }

  const isValid = await verifyPassword(password, user.hashedPassword);
  if (!isValid) {
    return { success: false, error: 'Invalid credentials', remaining: rateCheck.remaining };
  }

  // Reset rate limit on successful login
  resetRateLimit(ipAddress, 'login');

  const session = generateSessionToken(user.userId);

  return {
    success: true,
    userId: user.userId,
    token: session.token,
    expiresAt: session.expiresAt,
  };
}

function logoutUser(token) {
  return revokeSessionToken(token);
}

function authenticateRequest(token) {
  const session = validateSessionToken(token);
  if (!session) {
    return { authenticated: false, error: 'Invalid or expired token' };
  }
  return { authenticated: true, userId: session.userId };
}

